import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';

export type TestimonialVm = {
  id: string;
  name: string;
  role: 'student' | 'parent' | 'teacher';
  avatar: string;
  content: string;
  rating: number;
  date: string;
};

@Component({
  selector: 'app-testimonials',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './testimonials.component.html'
})
export class TestimonialsComponent {
  isLoading = signal(true);
  selectedRole = signal('all');

  testimonials = signal<TestimonialVm[]>([
    {
      id: '1',
      name: 'Youssef Amrani',
      role: 'student',
      avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?auto=format&fit=crop&w=150&q=60',
      content: 'Excellent plateforme ! Les cours sont très bien expliqués et les profs sont pédagogues. J\'ai amélioré mes notes en maths de 8 à 15 en quelques mois. Je recommande fortement !',
      rating: 5,
      date: '2026-03-15'
    },
    {
      id: '2',
      name: 'Mme. Fatima El Amrani',
      role: 'parent',
      avatar: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?auto=format&fit=crop&w=150&q=60',
      content: 'Mes enfants adorent cette plateforme. Ils peuvent réviser à leur rythme et les sessions live sont très interactives. En tant que parent, je peux suivre leur progression facilement. Merci EduPlatform !',
      rating: 5,
      date: '2026-03-18'
    },
    {
      id: '3',
      name: 'Sofia Benali',
      role: 'student',
      avatar: 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?auto=format&fit=crop&w=150&q=60',
      content: 'La plateforme m\'a beaucoup aidée pour préparer mon Bac. Les résumés de cours sont clairs et les examens blancs m\'ont permis de m\'entraîner efficacement. J\'ai eu mon Bac avec mention !',
      rating: 5,
      date: '2026-03-10'
    },
    {
      id: '4',
      name: 'M. Amine Idrissi',
      role: 'teacher',
      avatar: 'https://images.unsplash.com/photo-1560250097-0b93528c311a?auto=format&fit=crop&w=150&q=60',
      content: 'En tant que professeur, je trouve cette plateforme très bien conçue. Les outils pour créer des cours et suivre les étudiants sont excellents. L\'équipe technique est très réactive.',
      rating: 5,
      date: '2026-03-12'
    },
    {
      id: '5',
      name: 'Ali El Fassi',
      role: 'student',
      avatar: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&w=150&q=60',
      content: 'Les sessions live sont super interactives ! On peut poser des questions en direct et le prof répond immédiatement. C\'est comme être en classe mais depuis chez soi. Top !',
      rating: 4,
      date: '2026-03-20'
    },
    {
      id: '6',
      name: 'M. Rachid El Mansouri',
      role: 'parent',
      avatar: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&w=150&q=60',
      content: 'Je suis impresionné par la qualité des cours. Mon fils qui était en difficulté en physique a repris confiance en lui grâce aux explications claires des profs. Merci pour votre travail !',
      rating: 5,
      date: '2026-03-08'
    }
  ]);

  filteredTestimonials() {
    if (this.selectedRole() === 'all') {
      return this.testimonials();
    }
    return this.testimonials().filter(t => t.role === this.selectedRole());
  }

  getRoleLabel(role: string): string {
    switch (role) {
      case 'student': return 'Étudiant';
      case 'parent': return 'Parent';
      case 'teacher': return 'Professeur';
      default: return role;
    }
  }

  getRoleEmoji(role: string): string {
    switch (role) {
      case 'student': return '👨‍🎓';
      case 'parent': return '👨‍👩‍👧';
      case 'teacher': return '👨‍🏫';
      default: return '👤';
    }
  }

  constructor() {
    setTimeout(() => this.isLoading.set(false), 500);
  }

  filterByRole(role: string) {
    this.selectedRole.set(role);
  }
}
<div class="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50 py-12">
  <div class="max-w-7xl mx-auto px-4">
    <!-- Header -->
    <div class="text-center mb-12">
      <span class="text-[#FF6D00] font-semibold text-sm uppercase tracking-wider">Témoignages</span>
      <h1 class="text-4xl md:text-5xl font-bold text-gray-900 mt-2">
        💬 Ce qu'ils <span class="text-transparent bg-clip-text bg-gradient-to-r from-[#1A73E8] to-[#FF6D00]">pensent</span>
      </h1>
      <p class="mt-4 text-lg text-gray-600 max-w-2xl mx-auto">
        Découvrez les retours d'expérience de notre communauté
      </p>
    </div>

    <!-- Filters -->
    <div class="flex flex-wrap justify-center gap-3 mb-10">
      <button 
        *ngFor="let role of ['all', 'student', 'parent', 'teacher']"
        (click)="filterByRole(role)"
        [class]="selectedRole() === role 
          ? 'bg-gradient-to-r from-[#1A73E8] to-[#FF6D00] text-white' 
          : 'bg-white text-gray-700 hover:bg-gray-100'"
        class="px-5 py-2.5 rounded-full font-medium transition-all hover:shadow-lg flex items-center gap-2">
        <span *ngIf="role === 'all'">👥</span>
        <span *ngIf="role === 'student'">👨‍🎓</span>
        <span *ngIf="role === 'parent'">👨‍👩‍👧</span>
        <span *ngIf="role === 'teacher'">👨‍🏫</span>
        {{ role === 'all' ? 'Tous' : getRoleLabel(role) }}
      </button>
    </div>

    <!-- Stats -->
    <div class="grid grid-cols-3 gap-4 mb-12 max-w-2xl mx-auto">
      <div class="bg-white rounded-2xl p-4 shadow-lg text-center">
        <div class="text-3xl font-bold text-[#1A73E8]">4.8</div>
        <div class="text-gray-500 text-sm">Note moyenne</div>
      </div>
      <div class="bg-white rounded-2xl p-4 shadow-lg text-center">
        <div class="text-3xl font-bold text-[#FF6D00]">95%</div>
        <div class="text-gray-500 text-sm">Satisfaction</div>
      </div>
      <div class="bg-white rounded-2xl p-4 shadow-lg text-center">
        <div class="text-3xl font-bold text-green-600">6</div>
        <div class="text-gray-500 text-sm">Témoignages</div>
      </div>
    </div>

    <!-- Loading -->
    <div *ngIf="isLoading()" class="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
      <div *ngFor="let x of [1,2,3,4,5,6]" class="bg-white rounded-2xl p-6 shadow-lg">
        <div class="flex items-center gap-4 mb-4">
          <div class="w-14 h-14 rounded-full bg-gray-200 animate-pulse"></div>
          <div class="flex-1">
            <div class="h-4 bg-gray-200 rounded animate-pulse w-24 mb-2"></div>
            <div class="h-3 bg-gray-200 rounded animate-pulse w-16"></div>
          </div>
        </div>
        <div class="h-20 bg-gray-200 rounded animate-pulse"></div>
      </div>
    </div>

    <!-- Testimonials Grid -->
    <div *ngIf="!isLoading()" class="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
      <div *ngFor="let testimonial of filteredTestimonials()" 
           class="bg-white rounded-3xl p-6 shadow-lg hover:shadow-xl transition-all hover:-translate-y-2">
        <!-- Header -->
        <div class="flex items-start gap-4 mb-4">
          <img [src]="testimonial.avatar" [alt]="testimonial.name" 
               class="w-14 h-14 rounded-full object-cover border-2 border-[#1A73E8]">
          <div class="flex-1">
            <h3 class="font-bold text-gray-900">{{ testimonial.name }}</h3>
            <div class="flex items-center gap-2">
              <span class="text-lg">{{ getRoleEmoji(testimonial.role) }}</span>
              <span class="text-sm text-gray-500">{{ getRoleLabel(testimonial.role) }}</span>
            </div>
          </div>
          <div class="flex">
            <span *ngFor="let star of [1,2,3,4,5]" 
                  class="text-lg" 
                  [class]="star <= testimonial.rating ? 'text-yellow-400' : 'text-gray-300'">★</span>
          </div>
        </div>

        <!-- Content -->
        <p class="text-gray-600 leading-relaxed">"{{ testimonial.content }}"</p>

        <!-- Date -->
        <div class="mt-4 pt-4 border-t border-gray-100 text-sm text-gray-400">
          {{ testimonial.date | date:'dd MMMM yyyy' }}
        </div>
      </div>
    </div>

    <!-- CTA -->
    <div class="mt-16 bg-white rounded-3xl p-10 shadow-xl">
      <div class="text-center">
        <h2 class="text-2xl font-bold text-gray-900 mb-4">Vous avez utilisé EduPlatform ?</h2>
        <p class="text-gray-600 mb-6">Partagez votre expérience avec notre communauté</p>
        <button class="bg-gradient-to-r from-[#1A73E8] to-[#FF6D00] text-white px-8 py-3 rounded-xl font-bold hover:shadow-lg transition-all hover:scale-105">
          Laisser un témoignage
        </button>
      </div>
    </div>
  </div>
</div>
